import{_ as a,c as t,o as n,a4 as r}from"./chunks/framework.Cjj1onnZ.js";const h=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"en/01-intro/03-quick-start.md","filePath":"en/01-intro/03-quick-start.md"}'),i={name:"en/01-intro/03-quick-start.md"};function o(s,e,p,l,c,d){return n(),t("div",{"data-pagefind-body":!0},e[0]||(e[0]=[r('<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to “Quick Start”">​</a></h1><h2 id="pre-development-preparation" tabindex="-1">Pre-development Preparation <a class="header-anchor" href="#pre-development-preparation" aria-label="Permalink to “Pre-development Preparation”">​</a></h2><h3 id="development-environment-setup" tabindex="-1">Development Environment Setup <a class="header-anchor" href="#development-environment-setup" aria-label="Permalink to “Development Environment Setup”">​</a></h3><p>This step aims to provide the necessary development environment for extension package development.</p><p>For detailed information, see <a href="./../02-development/01-environment.html">Development Environment Setup</a></p><h3 id="entering-the-development-phase" tabindex="-1">Entering the Development Phase <a class="header-anchor" href="#entering-the-development-phase" aria-label="Permalink to “Entering the Development Phase”">​</a></h3><p>After completing environment setup, developers can choose the functionality they need and follow the corresponding documentation for development.</p><h4 id="developing-web-mini-programs" tabindex="-1">Developing Web Mini Programs <a class="header-anchor" href="#developing-web-mini-programs" aria-label="Permalink to “Developing Web Mini Programs”">​</a></h4><p>Web Mini Program functionality supports developers in creating pages that meet custom requirements.</p><p>For detailed content and operation steps, see: <a href="./../02-development/02-quick-start/01-web-mini-program.html">Developing Web Mini Programs</a></p><h4 id="developing-easy-services" tabindex="-1">Developing Easy Services <a class="header-anchor" href="#developing-easy-services" aria-label="Permalink to “Developing Easy Services”">​</a></h4><p>Easy Service is a special type of service where users only need to write a Python file with arbitrary functions to generate an HTTP service that can be called by Web Mini Programs or <code>CALL_SERVICE</code> instructions.</p><p>For detailed content and operation steps, see: <a href="./../02-development/02-quick-start/02-easy-service.html">Easy Service Development</a></p><h4 id="developing-general-services" tabindex="-1">Developing General Services <a class="header-anchor" href="#developing-general-services" aria-label="Permalink to “Developing General Services”">​</a></h4><p>Users can run a service in the AP version for querying robot status, setting robot parameters, controlling robot motion, or custom functionalities. This service runs independently in the background and can be used by Web Mini Programs or other programs.</p><p>For detailed content and operation steps, see: <a href="./../02-development/02-quick-start/03-general-service.html">General Service Development</a></p>',16)]))}const v=a(i,[["render",o]]);export{h as __pageData,v as default};
